<script setup lang="ts">withDefaults(defineProps<{name:string;avatar:string;sub?:string;followers?:number;posts?:number;clubs?:number;selected?:boolean;followed?:boolean}>(),{})</script><template><article class="xj-card xj-user-card" :style="selected?{borderColor:'#62D991',boxShadow:'0 0 0 3px rgba(34,197,94,.08),var(--xj-shadow-card)'}:{}"><img :src="avatar" class="xj-avatar"/><div class="xj-user-name">{{name}} <span style="color:var(--xj-green);font-size:11px">●</span></div><div class="xj-user-sub">{{sub}}</div><div class="xj-user-stats"><div><b>{{followers||0}}</b><span>关注</span></div><div><b>{{posts||0}}</b><span>内容</span></div><div><b>{{clubs||0}}</b><span>社团</span></div></div><button class="xj-btn sm" :class="followed?'secondary':'study'" style="width:100%">{{followed?'已关注':'+ 关注'}}</button></article></template>
